import React, { useMemo } from 'react';
import { SearchInput } from '@linm-soft/common-components';
import type { MaterialDto } from '../../services/kt/models';
import { createMaterialSearchConfig } from './materialSearchConfig';
import df from '../../styles/documentForm.module.css';

export interface LineMaterialSearchCellProps {
  materialCode: string;
  materialName: string;
  error?: string;
  disabled?: boolean;
  onSelect: (material: MaterialDto) => void;
  onClear: () => void;
  testId?: string;
  cellId?: string;
  /** Card stack / header compact — `data-label` trên `<td>` */
  dataLabel?: string;
}

export const LineMaterialSearchCell: React.FC<LineMaterialSearchCellProps> = ({
  materialCode,
  materialName,
  error,
  disabled,
  onSelect,
  onClear,
  testId,
  cellId,
  dataLabel = 'Mã VT / Tên VT',
}) => {
  const config = useMemo(() => createMaterialSearchConfig(), []);
  const materialDisplay = materialCode && materialName
    ? `${materialCode} - ${materialName}`
    : (materialCode || materialName);

  return (
    <td
      id={cellId}
      colSpan={2}
      className={df.tdMaterialSearch}
      data-testid={testId}
      data-label={dataLabel}
    >
      <SearchInput
        config={config}
        value={materialCode}
        primaryDisplay={materialDisplay}
        onChange={onSelect}
        onClear={onClear}
        showLabel={false}
        showSecondaryInput={false}
        error={error}
        className={df.lineMaterialSearch}
        disabled={disabled}
      />
    </td>
  );
};

export const MaterialLineTableHeaders: React.FC = () => (
  <>
    <th className={df.thMatCode}>Mã VT</th>
    <th className={df.thMatName}>Tên VT</th>
  </>
);
