import type { AccountSearchApi } from '@linm-soft/common-components';
import { ktService } from '../../services/kt/ktService';
import { mapAccountSearchRecord } from './mapAccountSearchRecord';

/** Selected TK — single-field label (`AccountSearchInput` getSingleDisplay). */
export function formatAccountDisplay(code: string, name?: string): string {
  const c = code?.trim() ?? '';
  const n = name?.trim() ?? '';
  if (c && n) return `${c} — ${n}`;
  return c || n;
}

/** Finance MFE adapter — `GET /master/accounts` via ktService. */
export const erpFinanceAccountSearchApi: AccountSearchApi = {
  search: async ({ search, page, pageSize, isActive, isDetail, asOfDate, forPosting }) => {
    const res = await ktService.searchAccounts({
      search,
      page,
      pageSize,
      isActive: isActive ?? true,
      isDetail,
      asOfDate,
      forPosting,
    });
    return {
      items: res.items.map(mapAccountSearchRecord),
      page: res.page,
      totalCount: res.totalCount,
    };
  },
  loadCatalog: async (query) => {
    const res = await ktService.searchAccounts({
      isActive: true,
      page: 1,
      pageSize: 500,
      asOfDate: query?.asOfDate,
      forPosting: query?.forPosting,
    });
    return res.items.map(mapAccountSearchRecord);
  },
};
